class RedisSessionInterface:
    def __init__(self, redis_client, prefix='session:'):
        self.redis = redis_client
        self.prefix = prefix

    def generate_sid(self):
        return str(uuid.uuid4())

    def get_session_id(self):
        return request.cookies.get('session_id')

    def load_session(self, session_id):
        if not session_id:
            return {}
        
        key = f"{self.prefix}{session_id}"
        data = self.redis.get(key)
        
        if data:
            try:
                return json.loads(data)
            except:
                return {}
        return {}

    def save_session(self, session_id, session_data, expiry=86400):
        key = f"{self.prefix}{session_id}"
        self.redis.setex(key, expiry, json.dumps(session_data))

    def delete_session(self, session_id):
        key = f"{self.prefix}{session_id}"
        self.redis.delete(key)


session_interface = RedisSessionInterface(redis_session_client)


def cache_query(ttl=300, key_prefix='query'):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_data = f"{key_prefix}:{func.__name__}:{str(args)}:{str(sorted(kwargs.items()))}"
            cache_key = hashlib.md5(cache_key_data.encode()).hexdigest()
            
            cached_result = redis_cache_client.get(cache_key)
            
            if cached_result is not None:
                return pickle.loads(cached_result)
            
            result = func(*args, **kwargs)
            
            redis_cache_client.setex(
                cache_key,
                ttl,
                pickle.dumps(result)
            )
            
            return result
        
        return wrapper
    return decorator


def invalidate_cache(key_prefix='query', func_name=None):
    pattern = f"{key_prefix}:{func_name}:*" if func_name else f"{key_prefix}:*"
    
    cursor = 0
    while True:
        cursor, keys = redis_cache_client.scan(cursor, match=pattern, count=100)
        if keys:
            redis_cache_client.delete(*keys)
        if cursor == 0:
            break


@app.before_request
def load_session_data():
    session_id = session_interface.get_session_id()
    
    if session_id:
        request.session_data = session_interface.load_session(session_id)
        request.session_id = session_id
    else:
        request.session_data = {}
        request.session_id = None


@app.after_request
def save_session_data(response):
    if hasattr(request, 'session_data') and request.session_data:
        if not request.session_id:
            request.session_id = session_interface.generate_sid()
            response.set_cookie('session_id', request.session_id, 
                              max_age=86400, httponly=True, samesite='Lax')
        
        session_interface.save_session(request.session_id, request.session_data)
    
    return response


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    
    if not username:
        return jsonify({'error': 'Username required'}), 400
    
    request.session_data['username'] = username
    request.session_data['logged_in'] = True
    
    return jsonify({
        'message': 'Login successful',
        'session_id': request.session_id
    })


@app.route('/logout', methods=['POST'])
def logout():
    if request.session_id:
        session_interface.delete_session(request.session_id)
        request.session_data = {}
    
    response = jsonify({'message': 'Logout successful'})
    response.set_cookie('session_id', '', expires=0)
    return response


